  detail5_b1: '매 수업 정확도 트래킹', detail5_b2: '오답 유형별 통계', detail5_b3: '기간별 성취도 분석',

  // 프로그램 섹션
  prog_section_badge: '교육 프로그램',
  prog_section_h2a: '모든 학년, 모든 수준을 위한',
  prog_section_h2b: '맞춤형 과정',

  prog0_icon: '🌱', prog0_grade: '초등', prog0_sub: '3~6학년',
  prog0_desc: '수학의 기초 개념과 연산 원리를 탄탄하게. 수학을 좋아하는 아이로 만들어 드립니다.',
  prog1_icon: '📈', prog1_grade: '중등', prog1_sub: '1~3학년',
